<template>
  <view class="profile-container">
    <view class="profile-card">
      <!-- 头像修改 -->
      <view class="form-item avatar-item" @tap="chooseAvatar">
        <text class="label">头像</text>
        <view class="right-content">
          <image :src="formData.avatar || '/static/images/icon-user.png'" class="avatar-img" mode="aspectFill"></image>
          <image src="/static/images/icon-arrow-right.png" class="arrow-icon"></image>
        </view>
      </view>

      <!-- 昵称修改 -->
      <view class="form-item">
        <text class="label">昵称</text>
        <input class="input" v-model="formData.nickname" placeholder="请输入昵称" maxlength="20" />
      </view>

      <!-- 手机号修改 -->
      <view class="form-item">
        <text class="label">手机号</text>
        <input class="input" v-model="formData.phone" placeholder="请输入手机号" type="number" maxlength="11" />
      </view>
    </view>

    <view class="footer-btn-box">
      <button class="save-btn" @tap="handleSave">保存修改</button>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onLoad } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request, { upload } from '@/utils/request';

const userStore = useUserStore();
const formData = ref({
  nickname: '',
  avatar: '',
  phone: ''
});

onLoad(() => {
  getUserDetail();
});

// 获取用户详情
const getUserDetail = async () => {
  uni.showLoading({ title: '加载中...' });
  try {
    const res = await request({
      url: '/api/user/detail/get',
      method: 'GET'
    });
    if (res.success) {
      formData.value = {
        nickname: res.data.nickname || '',
        avatar: res.data.avatar || '',
        phone: res.data.phone || ''
      };
    }
  } catch (error) {
    console.error('获取用户信息失败:', error);
  } finally {
    uni.hideLoading();
  }
};

// 选择并上传头像
const chooseAvatar = () => {
  console.log('--- chooseAvatar triggered ---');
  
  // 网页端直接使用 uni.chooseImage
  uni.chooseImage({
    count: 1,
    sizeType: ['compressed'],
    sourceType: ['album', 'camera'],
    success: (res) => {
      console.log('--- chooseImage success ---', res.tempFilePaths);
      const tempFilePath = res.tempFilePaths[0];
      uploadAvatar(tempFilePath);
    },
    fail: (err) => {
      console.error('--- chooseImage fail ---', err);
      if (err.errMsg && err.errMsg.indexOf('cancel') === -1) {
        uni.showToast({ title: '选择头像失败', icon: 'none' });
      }
    }
  });
};

const uploadAvatar = async (filePath) => {
  uni.showLoading({ title: '上传中...' });
  try {
    const res = await upload({
      url: '/api/upload/image',
      filePath: filePath,
      name: 'file'
    });
    if (res.success) {
      formData.value.avatar = res.data;
      uni.showToast({ title: '上传成功', icon: 'success' });
    } else {
      uni.showToast({ title: res.message || '上传失败', icon: 'none' });
    }
  } catch (error) {
    console.error('上传头像失败:', error);
  } finally {
    uni.hideLoading();
  }
};

// 校验手机号
const validatePhone = (phone) => {
  return /^1[3-9]\d{9}$/.test(phone);
};

// 保存修改
const handleSave = async () => {
  if (!formData.value.nickname.trim()) {
    return uni.showToast({ title: '昵称不能为空', icon: 'none' });
  }
  if (formData.value.phone && !validatePhone(formData.value.phone)) {
    return uni.showToast({ title: '手机号格式不正确', icon: 'none' });
  }

  uni.showLoading({ title: '保存中...' });
  try {
    const res = await request({
      url: '/api/user/detail/update',
      method: 'PUT',
      data: formData.value
    });
    if (res.success) {
      uni.showToast({ title: '修改成功', icon: 'success' });
      // 更新 Pinia 中的用户信息
      userStore.updateUserInfo(formData.value);
      setTimeout(() => {
        uni.navigateBack();
      }, 1500);
    } else {
      uni.showToast({ title: res.message || '修改失败', icon: 'none' });
    }
  } catch (error) {
    console.error('更新用户信息失败:', error);
  } finally {
    uni.hideLoading();
  }
};
</script>

